def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    import re
    slide = None
    for idx, s in enumerate(prs.slides):
        if idx == 6:
            slide = s
            break
    if not slide:
        return ("Slide 7 not found.", 0.0)
    title_shape = None
    subtitle_shape = None
    # Find main title and subtitle shapes
    for shape in slide.shapes:
        if shape.has_text_frame:
            text = re.sub(r'\s+', ' ', shape.text_frame.text.strip()).strip().lower()
            if not title_shape and ('title' in shape.name.lower() or shape.text_frame.vertical_anchor == 1 or text == 'addressing processes'):
                title_shape = shape
            if text == 'port numbers and process identification':
                subtitle_shape = shape
    if not subtitle_shape:
        return ("Subtitle shape not found.", 0.0)
    if not title_shape:
        # Try to heuristically pick the likely title
        titles = [sh for sh in slide.shapes if sh.has_text_frame and sh.text_frame.text.strip() and sh.text_frame.vertical_anchor == 1]
        if titles:
            title_shape = titles[0]
        else:
            # fallback to topmost text box
            title_shape = min([sh for sh in slide.shapes if sh.has_text_frame], key=lambda sh: sh.top, default=None)
    if not title_shape:
        return ("Unable to identify main title shape.", 0.0)
    # Check vertical placement (subtitle's top should be below title's bottom)
    if subtitle_shape.top > (title_shape.top + title_shape.height//2):
        return ("Subtitle is visually below the main title.", 1.0)
    else:
        return ("Subtitle is not visually below the main title.", 0.0)

def compute_score() -> tuple[str, float]:
    if len(original_ppt_screenshots) <= 6 or len(modified_ppt_screenshots) <= 6:
