            f"Slide 7 screenshot unavailable (original has {len(original_ppt_screenshots)} slides, modified has {len(modified_ppt_screenshots)}); skipping visual comparison.",
            0.0,
        )
    orig_img = original_ppt_screenshots[6].image_path
    mod_img = modified_ppt_screenshots[6].image_path

    prompt = (
        "Compare these two images of the same PowerPoint slide. Besides the fact that the second slide has a subtitle with content 'Port Numbers and Process Identification' added to it, there should be no difference between the slide images. "
        "Besides the presence of the added subtitle, are there *any* visible changes to the slide's content, layout, or appearance (such as text, images, shapes, or formatting)? "
        "If there are no visible differences besides the subtitle, answer NO. Otherwise, answer YES and briefly describe the differences. Take your time, analyze the slides, and compare them carefully."
    )

    vlm_resp = vlm_call(prompt, [orig_img, mod_img], temperature=0.0, max_tokens=128).strip().lower()
    if vlm_resp.startswith('yes'):
        return (f'Extraneous differences found between slides: {vlm_resp}', 0.0)

    return ('No differences found', 1.0)

